"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   passageSlovakia2026: () => (/* binding */ passageSlovakia2026)\n/* harmony export */ });\n// campaigns/passage-slovakia-2026.ts\n/**\n * PASSAGE: Slovakia 2026 — DAT fundraising campaign\n *\n * Goal: Raise the funds needed to bring artists into community in Slovakia this summer,\n * widening participation for both traveling artists and local artists, and supporting\n * shared creative work that builds voice, confidence, belonging, leadership, and possibility.\n *\n * Primary link: https://dramaticadventure.com/passage/slovakia\n * Contextual link: https://dramaticadventure.com/passage\n *\n * LIVE: matchActive is false until a real match underwriter is confirmed.\n * Seed the Neon DB with a real donation before publishing to avoid a zero start.\n */ const passageSlovakia2026 = {\n    // ── Identity ──────────────────────────────────────────────────────\n    id: \"passage-slovakia-2026\",\n    status: \"active\",\n    // ── Hero ──────────────────────────────────────────────────────────\n    title: \"Get Artists to Slovakia This Summer\",\n    eyebrow: \"PASSAGE: SLOVAKIA 2026\",\n    tagline: \"Your gift will help artists and communities create work that builds voice, confidence, belonging, and possibility.\",\n    heroCopy: \"This summer, Dramatic Adventure Theatre will bring artists to Eastern Slovakia to make theatre in real relationship with community — side by side with local partners, local artists, and young people whose voices and stories belong front and center.\\n\\nIn many of the communities DAT serves, meaningful access to arts education and programming is limited. And for many artists — especially those with fewer resources, fewer connections, or fewer opportunities to travel — work like this can feel out of reach. Your gift helps close that gap.\\n\\nYour gift opens this project to more artists, including overlooked and less-resourced traveling artists as well as local artists whose presence is essential to the honesty, depth, and impact of the work. And your gift helps create theatre that amplifies local voices, strengthens confidence and belonging, preserves culture, grows creative problem-solving and leadership, and gives people space to imagine beyond the immediate needs of the moment.\\n\\nPASSAGE does not end when the residency ends. The work deepens with DAT Drama Clubs, and each artist involved will be imprinted by the experience. This community-rooted way of making work will find its way into the artists' future classrooms, rehearsal rooms, and home communities.\\n\\nTogether we can create magic in Slovakia this summer.\",\n    heroImage: \"/images/rehearsing-nitra.jpg\",\n    heroImageFocus: \"center\",\n    heroImageCredit: \"Rehearsals at Divadlo Andrea Bagara, Nitra\",\n    // ── Goal ──────────────────────────────────────────────────────────\n    goalAmount: 12000,\n    currency: \"usd\",\n    // ── Deadline ──────────────────────────────────────────────────────\n    deadline: \"2026-06-30\",\n    // ── Match ─────────────────────────────────────────────────────────\n    matchActive: false,\n    matchDescription: \"\",\n    matchCap: 0,\n    matchUnderwriterEmail: \"hello@dramaticadventure.com\",\n    matchUnderwriterLabel: \"Interested in underwriting artist access?\",\n    // ── Donor callout ─────────────────────────────────────────────────\n    donorCallout: \"A gift of a few hundred dollars helps close two access gaps at once: bringing meaningful theatre into communities that deserve more of it, and opening this life-shaping work to artists who might otherwise be left out.\",\n    // ── Share ─────────────────────────────────────────────────────────\n    shareText: \"Help DAT bring artists to Slovakia this summer so artists and communities can create work that builds voice, confidence, belonging, leadership, and possibility.\",\n    // ── Giving ────────────────────────────────────────────────────────\n    giveAmounts: [\n        50,\n        100,\n        250,\n        500,\n        1000,\n        2500\n    ],\n    oneTimeAmounts: [\n        50,\n        100,\n        250,\n        500,\n        1000,\n        2500\n    ],\n    monthlyAmounts: [\n        25,\n        50,\n        100,\n        250\n    ],\n    defaultAmount: 250,\n    allowMonthly: false,\n    // ── Frequency-aware impact copy ───────────────────────────────────\n    oneTimeImpactCopy: \"Your gift helps make PASSAGE possible for more artists and supports community-rooted theatre that can amplify local voices, strengthen belonging, grow leadership, preserve culture, and widen what feels possible.\",\n    monthlyImpactCopy: \"Monthly giving is currently disabled for this time-bound campaign so the focus stays on getting artists to Slovakia this summer.\",\n    // ── Gift impact ───────────────────────────────────────────────────\n    giftImpact: [\n        {\n            amount: 50,\n            description: \"Helps strengthen the shared creative process that gives young people and artists space to be seen, heard, and valued.\",\n            icon: \"✨\"\n        },\n        {\n            amount: 100,\n            description: \"Supports theatre-making in community that builds confidence, communication, and creative expression.\",\n            icon: \"🎭\"\n        },\n        {\n            amount: 250,\n            description: \"Helps make participation possible for an artist whose presence can deepen the work and widen who gets to take part.\",\n            icon: \"🧭\"\n        },\n        {\n            amount: 500,\n            description: \"Provides meaningful support for community-rooted work that can grow belonging, leadership, and possibility.\",\n            icon: \"✈️\"\n        },\n        {\n            amount: 1000,\n            description: \"Helps widen the circle of artists and strengthen the ripple effects this work can have in community and beyond.\",\n            icon: \"⭐\"\n        },\n        {\n            amount: 2500,\n            description: \"Makes a leadership-level investment in shared creation that can shape artists, strengthen community, and leave lasting impact.\",\n            icon: \"🔥\"\n        }\n    ],\n    monthlyGiftImpact: [\n        {\n            amount: 25,\n            description: \"Would sustain ongoing coordination and relationship-building with Slovak partners in future phases of the work.\",\n            icon: \"🤝\"\n        },\n        {\n            amount: 50,\n            description: \"Would support future community-rooted theatre activity and continued partnership after the residency.\",\n            icon: \"🎭\"\n        },\n        {\n            amount: 100,\n            description: \"Would help maintain ongoing mentorship, collaboration, and local follow-through beyond a single trip.\",\n            icon: \"☀️\"\n        },\n        {\n            amount: 250,\n            description: \"Would help sustain DAT's long-term community relationships in Slovakia over time.\",\n            icon: \"⭐\"\n        }\n    ],\n    // ── Stretch goals ─────────────────────────────────────────────────\n    stretchGoals: [\n        {\n            amount: 15000,\n            title: \"A Wider Circle of Artists\",\n            description: \"Go beyond the core goal and open PASSAGE to more artists whose presence can deepen the work and widen who gets to participate.\"\n        },\n        {\n            amount: 18000,\n            title: \"Stronger Community Impact\",\n            description: \"Increase support for local artists and collaborators in Slovakia so the work can build deeper confidence, belonging, leadership, cultural pride, and community connection.\"\n        },\n        {\n            amount: 22000,\n            title: \"Longer Ripples Beyond the Summer\",\n            description: \"Invest more deeply in the relationships, local leadership, and shared creative process that continue shaping artists and community long after the residency ends.\"\n        }\n    ],\n    // ── Testimonials ──────────────────────────────────────────────────\n    testimonials: [\n        {\n            id: \"t-passage-1\",\n            quote: \"What changed me was not just being in Slovakia. It was making something in real relationship with people whose stories, artistry, and presence changed how I understand theatre and community.\",\n            name: \"DAT Artist\",\n            role: \"PASSAGE Participant\"\n        },\n        {\n            id: \"t-passage-2\",\n            quote: \"This work matters because it helps people find voice, confidence, connection, and possibility through shared creation. It strengthens artists, young people, and community at the same time.\",\n            name: \"ETP Slovensko\",\n            role: \"Community Collaborator\"\n        }\n    ],\n    // ── Linked content (dynamic references) ───────────────────────────\n    alumniSlugs: [\n        \"jesse-baxter\",\n        \"barbara-herucova\",\n        \"peter-petkovsek\",\n        \"mathilde-prosen-oldani\"\n    ],\n    dramaClubSlugs: [\n        \"lunik-ix-collective\"\n    ],\n    eventIds: [\n        \"dat-summer-launch-2026\",\n        \"passage-sendoff-2026\",\n        \"joint-drama-club-showcase-slovakia-2026\",\n        \"passage-performance-party-2026\"\n    ],\n    storySlugs: [\n        \"drama-works\",\n        \"night-at-the-roma-museum\"\n    ],\n    // ── Gallery ───────────────────────────────────────────────────────\n    // Keep inline for now: the captions are campaign-specific.\n    gallery: [\n        {\n            src: \"/images/rehearsing-nitra.jpg\",\n            alt: \"DAT artists rehearsing in Nitra, Slovakia\",\n            caption: \"Rehearsals at ETP Slovensko partner school, Nitra\"\n        },\n        {\n            src: \"/images/performing-zanzibar.jpg\",\n            alt: \"DAT performance — community theatre in action\",\n            caption: \"The PASSAGE process: making theatre with the community\"\n        },\n        {\n            src: \"/images/teaching-amazon.jpg\",\n            alt: \"DAT teaching artist at work\",\n            caption: \"What artists carry home can keep rippling outward for years\"\n        }\n    ],\n    // ── Campaign updates ──────────────────────────────────────────────\n    updates: [\n        {\n            id: \"u-passage-4\",\n            date: \"2026-04-14\",\n            title: \"Why This Work Matters\",\n            body: \"PASSAGE is not just about getting artists to Slovakia. It is about creating shared work in community that can build voice, confidence, belonging, leadership, and possibility. Every gift helps widen that impact.\",\n            authorName: \"Jesse Baxter\",\n            authorRole: \"Artistic Director\"\n        },\n        {\n            id: \"u-passage-3\",\n            date: \"2026-04-13\",\n            title: \"36% Funded\",\n            body: \"We've crossed $4,300 toward our goal. Thank you for helping open this project to more artists and strengthen the community-rooted work at its heart.\",\n            authorName: \"Jesse Baxter\",\n            authorRole: \"Artistic Director\"\n        },\n        {\n            id: \"u-passage-2\",\n            date: \"2026-04-07\",\n            title: \"The Impact Begins in Community\",\n            body: \"This work only becomes real when artists are in relationship with community, making something together on the ground in Slovakia. That is where voice, belonging, confidence, and possibility begin.\",\n            authorName: \"DAT Team\"\n        },\n        {\n            id: \"u-passage-1\",\n            date: \"2026-04-01\",\n            title: \"Campaign Launched\",\n            body: \"We're raising funds to help bring artists to Slovakia this summer so PASSAGE can create the kind of shared work that strengthens artists, communities, and the future they imagine together.\",\n            authorName: \"DAT Team\"\n        }\n    ],\n    // ── Links ─────────────────────────────────────────────────────────\n    learnMoreUrl: \"https://dramaticadventure.com/passage/slovakia\",\n    secondaryUrl: \"https://dramaticadventure.com/passage\",\n    ambassadorUrl: \"https://dramaticadventure.com/passage/slovakia\",\n    // ── Archive state ─────────────────────────────────────────────────\n    archiveHeadline: \"Because you helped make this work possible.\",\n    archiveSummary: \"Thank you to every donor who helped open PASSAGE to more artists and bring shared creative work to life in Slovakia. What was built there — voice, confidence, belonging, leadership, and possibility — will keep rippling outward through artists, community, and the relationships that continue beyond the summer.\",\n    // ── Analytics ─────────────────────────────────────────────────────\n    utmCampaign: \"passage-slovakia-2026\"\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./campaigns/passage-slovakia-2026.ts\n");

