       // Rotating sites → leave coords undefined\n        lat: undefined,\n        lng: undefined\n    },\n    /* ============================\n     SLOVAKIA – NORTHERN & WESTERN\n     ============================ */ \"stara-lubovna-story-circle\": {\n        ...DRAMA_CLUB_TEMPLATE,\n        slug: \"stara-lubovna-story-circle\",\n        name: \"Stará Ľubovňa Story Circle\",\n        country: \"Slovakia\",\n        region: \"Northern Slovakia\",\n        city: \"Stará Ľubovňa\",\n        heroTextureTagline: \"Northern Slovakia • Castle Town\",\n        location: \"Community center & school gym\",\n        meetingPlace: \"Community center hall beneath the castle hill\",\n        shortBlurb: \"A mixed-community club where Roma and non-Roma youth shared stories across a small northern Slovak town.\",\n        cardImage: FALLBACK_IMAGE,\n        heroImage: FALLBACK_IMAGE,\n        gallery: [\n            {\n                src: FALLBACK_IMAGE,\n                alt: \"Stará Ľubovňa rehearsal in a school gym\"\n            }\n        ],\n        description: \"A mixed-community drama club in Stará Ľubovňa where Roma and non-Roma youth created original plays about family, migration, and small-town life.\",\n        whatHappens: \"Workshops break down into small ensembles where youth from different backgrounds play side by side, then bring their stories together into one shared piece.\",\n        originStory: \"Developed alongside local NGOs and educators, the club provided a neutral creative space for young people who rarely met outside of school.\",\n        language: \"Slovak / Romani\",\n        culturalExchangeLearn: \"We learn how small towns hold long histories—and how youth can interrupt inherited divisions.\",\n        culturalExchangeShare: \"We share collaboration tools that make shared creation possible across difference.\",\n        statusOverride: \"legacy\",\n        communityPartners: [\n            {\n                name: \"Local NGOs and educators\",\n  